mapper.select:
SELECT u.id, u.username, u.realname, d.depart_name as departName, u.phone, u.email, a.id as authId FROM ietm_auth a INNER JOIN sys_user u ON a.user_id = u.id LEFT JOIN sys_user_depart ud ON u.id = ud.user_id AND ud.is_main = 1 LEFT JOIN sys_depart d ON ud.dep_id = d.id WHERE a.obj_id = #{param.targetId}
AND a.obj_type = #{param.objType}
AND u.username LIKE CONCAT('%', #{param.username}, '%')
AND u.realname LIKE CONCAT('%', #{param.realname}, '%')
ORDER BY a.creation_date DESC

SELECT COUNT(1)
FROM ietm_auth
WHERE user_id = #{userId}
  AND obj_id = #{objId}
  AND obj_type = #{objType}

